<?php $h=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$pageTitle=$pageTitle??'';$pageDescription=$pageDescription??'';$breadcrumbs=$breadcrumbs??[];$primaryAction=$primaryAction??null; ?>
<header class="vo-page-header"><div class="vo-page-header__copy"><?php if($breadcrumbs): ?><nav class="vo-breadcrumbs" aria-label="Ruta de navegación"><?= $h(implode(' / ',$breadcrumbs)) ?></nav><?php endif; ?><h2 class="vo-page-title"><?= $h($pageTitle) ?></h2><?php if($pageDescription!==''): ?><p class="vo-page-description"><?= $h($pageDescription) ?></p><?php endif; ?></div><?php if(is_array($primaryAction)): ?><div class="vo-actions"><a class="vo-btn vo-btn--primary" href="<?= $h($primaryAction['url']??'#') ?>"><?= $h($primaryAction['label']??'Continuar') ?></a></div><?php endif; ?></header>
